// Expose State on window so the many `(window.State && State.X)` guards
// scattered through this file work. Top-level `const` in a classic <script>
// creates a lexical binding only — it does NOT attach to window. Without
// this alias every defensive `window.State && …` short-circuits to false,
// which is why the Clubs picker fell through to its FC-Familista fallback
// even when availableClubs was correctly populated by AppContext.load().
try { if (typeof window !== 'undefined') window.State = State; } catch (_) {}

// ── Structured network error ─────────────────────────────────────────────
class ApiError extends Error {
  constructor(opts) {
    super(opts.message || 'Request failed');
    this.name        = 'ApiError';
    this.code        = opts.code        || 'UNKNOWN';      // e.g. NETWORK, TIMEOUT, AUTH, RATE_LIMIT, SERVER, VALIDATION
    this.status      = opts.status      || 0;
    this.userMessage = opts.userMessage || this.message;
    this.cause       = opts.cause       || null;
    this.url         = opts.url         || null;
  }
}

function mapApiError(err, ctx) {
  // Already an ApiError → pass through
  if (err instanceof ApiError) return err;

  // AbortError (timeout)
  if (err && err.name === 'AbortError') {
    return new ApiError({
      code: 'TIMEOUT', status: 0, url: ctx.url, cause: err,
      message: 'Request timed out',
      userMessage: 'Connection timeout. The server is taking too long to respond.',
    });
  }
  // Native fetch failure → network/CORS/DNS
  if (err instanceof TypeError) {
    return new ApiError({
      code: 'NETWORK', status: 0, url: ctx.url, cause: err,
      message: err.message || 'Network error',
      userMessage: navigator.onLine === false
        ? 'You appear to be offline. Check your internet connection.'
        : 'Backend waking up… Please retry in a few seconds.',
    });
  }
  return new ApiError({
    code: 'UNKNOWN', status: 0, url: ctx.url, cause: err,
    message: (err && err.message) || 'Unknown error',
    userMessage: 'Something went wrong. Please retry.',
  });
}

function mapHttpStatus(status, body, url) {
  const apiMsg = body && (body.message || body.error);
  if (status === 0)                 return new ApiError({ code: 'NETWORK',    status, url, message: 'Network error',                userMessage: 'Backend waking up… Please retry in a few seconds.' });
  if (status === 401)               return new ApiError({ code: 'AUTH',       status, url, message: apiMsg || 'Unauthorized',       userMessage: apiMsg || 'Authentication failed. Please sign in again.' });
  if (status === 403)               return new ApiError({ code: 'FORBIDDEN',  status, url, message: apiMsg || 'Forbidden',          userMessage: apiMsg || 'You do not have permission to do that.' });
  if (status === 404)               return new ApiError({ code: 'NOT_FOUND',  status, url, message: apiMsg || 'Not found',          userMessage: apiMsg || 'The requested resource was not found.' });
  if (status === 408 || status === 504) return new ApiError({ code: 'TIMEOUT', status, url, message: apiMsg || 'Timeout',           userMessage: 'Connection timeout. Please retry.' });
  if (status === 429)               return new ApiError({ code: 'RATE_LIMIT', status, url, message: apiMsg || 'Too many requests',  userMessage: 'Too many requests. Slow down and retry shortly.' });
  if (status >= 500)                return new ApiError({ code: 'SERVER',     status, url, message: apiMsg || 'Server error',       userMessage: status === 502 || status === 503 ? 'Server unavailable. The backend may be restarting — please retry in 30s.' : 'Server error. Please retry shortly.' });
  if (status === 400 || status === 422) return new ApiError({ code: 'VALIDATION', status, url, message: apiMsg || 'Validation error', userMessage: apiMsg || 'Some fields are invalid.' });
  return new ApiError({ code: 'HTTP_' + status, status, url, message: apiMsg || ('HTTP ' + status), userMessage: apiMsg || ('Unexpected error (HTTP ' + status + ')') });
}

// ── Network logger (structured groups) ────────────────────────────────────
// Silent by default. Enable in DevTools with:  window.__NET_LOG = true
function netLog(kind, payload) {
  if (!(typeof window !== 'undefined' && window.__NET_LOG)) return;
  try {
    const stamp = new Date().toISOString().slice(11, 23);
    if (kind === 'req')  console.log('%c[net→] ' + stamp + '  ' + payload.method + ' ' + payload.url, 'color:#22C55E;font-weight:600;');
    else if (kind === 'res') console.log('%c[net✓] ' + stamp + '  ' + payload.status + ' ' + payload.method + ' ' + payload.url + '  (' + payload.dt + 'ms)', 'color:#16A34A;');
    else if (kind === 'err') console.warn('%c[net✗] ' + stamp + '  ' + payload.code + ' ' + payload.method + ' ' + payload.url + '  — ' + payload.message, 'color:#DC2626;font-weight:600;');
    else if (kind === 'retry') console.warn('%c[net⟳] ' + stamp + '  retry ' + payload.attempt + '/' + payload.total + ' after ' + payload.delay + 'ms  ' + payload.method + ' ' + payload.url, 'color:#D97706;');
  } catch (_) {}
}

// ── FamilistaAPI — the wrapper ───────────────────────────────────────────
const FamilistaAPI = (function () {
  let _refreshing = null; // Promise — coalesces concurrent refreshes

  function sleep(ms) { return new Promise((r) => setTimeout(r, ms)); }

  function withTimeout(promise, ms, controller) {
    return new Promise((resolve, reject) => {
      const t = setTimeout(() => {
        try { controller && controller.abort(); } catch (_) {}
        const e = new Error('AbortError'); e.name = 'AbortError';
        reject(e);
      }, ms);
      promise.then(
        (v) => { clearTimeout(t); resolve(v); },
        (e) => { clearTimeout(t); reject(e); }
      );
    });
  }

  async function rawFetch(method, url, opts) {
    opts = opts || {};
    const controller = new AbortController();
    const headers = Object.assign(
      { 'Accept': 'application/json' },
      opts.body !== undefined && !(opts.body instanceof FormData) ? { 'Content-Type': 'application/json' } : {},
      opts.headers || {},
      opts.auth !== false && State.token ? { 'Authorization': 'Bearer ' + State.token } : {}
    );

    const init = {
      method,
      headers,
      signal: controller.signal,
      credentials: 'include',
      body: opts.body === undefined ? undefined : (opts.body instanceof FormData ? opts.body : JSON.stringify(opts.body)),
    };

    const timeoutMs = opts.timeoutMs ||
      (State.backendHealthy === false ? FAM_CONFIG.COLD_START_TIMEOUT_MS : FAM_CONFIG.REQUEST_TIMEOUT_MS);

    const started = Date.now();
    netLog('req', { method, url });

    let res;
    try {
      res = await withTimeout(fetch(url, init), timeoutMs, controller);
    } catch (err) {
      const apiErr = mapApiError(err, { url });
      netLog('err', { code: apiErr.code, method, url, message: apiErr.message });
      throw apiErr;
    }

    const dt = Date.now() - started;
    let body = null;
    if (res.status !== 204) {
      const text = await res.text().catch(() => '');
      if (text) { try { body = JSON.parse(text); } catch (_) { body = { message: text }; } }
    }

    if (!res.ok) {
      const apiErr = mapHttpStatus(res.status, body, url);
      apiErr.body = body;
      netLog('err', { code: apiErr.code, method, url, message: apiErr.message + ' (' + dt + 'ms)' });
      throw apiErr;
    }

    netLog('res', { status: res.status, method, url, dt });
    return body;
  }

  function refreshTokens() {
    // refresh_token HttpOnly cookie is sent automatically — no manual token.
    if (_refreshing) return _refreshing;
    _refreshing = (async () => {
      try {
        const body = await rawFetch('POST', FAM_CONFIG.API_BASE + '/auth/refresh',
          { auth: false });
        const data = body && (body.data || body);
        const at   = data && (data.accessToken || (data.tokens && data.tokens.accessToken));
        if (!at) return false;
        State.token = at;   // update in-memory token for WS/SSE
        return true;
      } catch (_) {
        return false;
      } finally {
        _refreshing = null;
      }
    })();
    return _refreshing;
  }

  async function request(method, urlOrPath, opts) {
    opts = opts || {};
    const url = /^https?:/.test(urlOrPath) ? urlOrPath : (FAM_CONFIG.API_BASE + (urlOrPath.startsWith('/') ? '' : '/') + urlOrPath);
    const retryable = FAM_CONFIG.RETRYABLE_STATUSES;
    const maxAttempts = (opts.noRetry ? 0 : FAM_CONFIG.RETRY_COUNT) + 1;

    for (let attempt = 1; attempt <= maxAttempts; attempt++) {
      try {
        return await rawFetch(method, url, opts);
      } catch (err) {
        // 401 → one transparent refresh attempt
        if (err.status === 401 && !opts._refreshed && opts.auth !== false) {
          const ok = await refreshTokens();
          if (ok) return request(method, url, Object.assign({}, opts, { _refreshed: true }));
        }

        const isRetryable = retryable.indexOf(err.status) !== -1 || err.code === 'NETWORK' || err.code === 'TIMEOUT';
        if (!isRetryable || attempt >= maxAttempts) throw err;

        // Cold-start banner on first failure
        if (err.code === 'NETWORK' || err.code === 'TIMEOUT' || err.status >= 502) {
          State.backendHealthy = false;
          BackendHealth.notifyOffline(err);
        }

        const delay = FAM_CONFIG.RETRY_BACKOFF_MS * attempt;
        netLog('retry', { attempt, total: maxAttempts, delay, method, url });
        await sleep(delay);
      }
    }
    // unreachable — the loop either returns or throws
    throw new ApiError({ code: 'UNKNOWN', message: 'unreachable' });
  }

  return {
    request,
    get:    (path, opts) => request('GET',    path, opts),
    post:   (path, body, opts) => request('POST',   path, Object.assign({ body }, opts || {})),
    put:    (path, body, opts) => request('PUT',    path, Object.assign({ body }, opts || {})),
    patch:  (path, body, opts) => request('PATCH',  path, Object.assign({ body }, opts || {})),
    delete: (path, opts) => request('DELETE', path, opts),
    refreshTokens,
    rawFetch,
  };
})();

// ── Backend health monitor ───────────────────────────────────────────────
const BackendHealth = (function () {
  let pollTimer = null;
  let lastState = null;          // 'up' | 'down' | null

  function banner() { return document.getElementById('backend-banner'); }

  function show(text, kind) {
    let el = banner();
    if (!el) {
      el = document.createElement('div');
      el.id = 'backend-banner';
      el.className = 'backend-banner';
      document.body.appendChild(el);
    }
    el.className = 'backend-banner ' + (kind || 'warn') + ' show';
    el.innerHTML =
      '<span class="dot"></span>' +
      '<span class="msg">' + (text || '') + '</span>' +
      '<button class="retry" onclick="BackendHealth.retryNow()">Retry now</button>';
  }
  function hide() {
    const el = banner();
    if (el) el.classList.remove('show');
  }

  async function ping(timeoutMs) {
    timeoutMs = timeoutMs || FAM_CONFIG.HEALTH_PING_TIMEOUT_MS;
    try {
      const r = await FamilistaAPI.rawFetch('GET', FAM_CONFIG.HEALTH_URL, { auth: false, timeoutMs });
      if (r && r.status === 'ok') return true;
      return false;
    } catch (_) { return false; }
  }

  // Delegates to the one global guard so health pings / banner mutations are
  // suppressed whenever any editing UI is active (modal, drawer, focused field).
  function _modalIsOpen() {
    return (typeof isEditingUIActive === 'function')
      ? isEditingUIActive()
      : !!document.querySelector('.modal-bg.open');
  }

  async function check(initial) {
    // Never ping / mutate the DOM while a modal form is open — focus would be lost.
    if (!initial && _modalIsOpen()) return;
    const ok = await ping(initial ? FAM_CONFIG.HEALTH_BOOT_TIMEOUT_MS : undefined);
    if (ok) {
      State.backendHealthy = true;
      if (lastState !== 'up') {
        hide();
        if (lastState === 'down') showToast('Backend is back online ✓', 'success');
      }
      lastState = 'up';
    } else {
      State.backendHealthy = false;
      if (lastState !== 'down') {
        show('Backend waking up… retrying automatically.', 'warn');
      }
      lastState = 'down';
    }
    return ok;
  }

  function start() {
    stop();
    check(true);
    pollTimer = setInterval(check, FAM_CONFIG.HEALTH_PING_INTERVAL);

    if (typeof window !== 'undefined') {
      window.addEventListener('online',  () => { if (!_modalIsOpen()) { show('Network restored. Checking backend…', 'info'); check(); } });
      window.addEventListener('offline', () => { State.backendHealthy = false; show('You are offline.', 'warn'); });
      document.addEventListener('visibilitychange', () => { if (!document.hidden && !_modalIsOpen()) check(); });
    }
  }
  function stop() { if (pollTimer) { clearInterval(pollTimer); pollTimer = null; } }

  function notifyOffline(err) {
    // De-dupe: during a cold-start, request() retries up to 2 times PER
    // failing call, and loadAllData fires 5 parallel calls. Without this
    // guard, the banner's innerHTML was being replaced 10x in ~5 seconds
    // — each replacement re-mounted the .dot span, restarting the
    // badgePulse animation from 0 and producing visible page-wide
    // flicker. We only paint the banner ONCE per offline window; the
    // 30 s health-ping (check()) will hide() it when the backend recovers.
    if (lastState === 'down') return;
    const el = banner();
    if (el && el.classList.contains('show')) { lastState = 'down'; return; }
    const msg = err && err.userMessage || 'Backend is unreachable. Retrying…';
    show(msg, 'warn');
    lastState = 'down';
  }
  function retryNow() { check(); }

  return { start, stop, ping, check, notifyOffline, retryNow };
})();

// ── Legacy helpers — kept so the rest of the file works unchanged ────────
async function api(endpoint, options) {
  options = options || {};
  return FamilistaAPI.request(options.method || 'GET', endpoint, {
    body:    options.body,
    headers: options.headers,
  });
}

async function tryRefreshToken() { return FamilistaAPI.refreshTokens(); }

// ── AUTH ──
async function doLogin() {
  const email    = document.getElementById('login-email').value.trim();
  const password = document.getElementById('login-password').value;
  const btn      = document.getElementById('login-btn');
  const errEl    = document.getElementById('login-error');

  function err(msg) {
    errEl.textContent = msg;
    errEl.classList.add('show');
  }

  if (!email || !password) return err('Please enter email and password');

  btn.disabled = true;
  btn.textContent = 'Signing in…';
  errEl.classList.remove('show');

  // Optional pre-flight: if backend is known-down, hint the user.
  if (State.backendHealthy === false) {
    btn.textContent = 'Waking backend…';
    await BackendHealth.check();
  }

  try {
    // FamilistaAPI handles: timeout, retry on 502/503/504, cold-start,
    // banner, structured errors with .userMessage.
    const data = await FamilistaAPI.post('/auth/login', { email, password }, { auth: false });

    // Response envelope: { success, data: { user, tokens: { accessToken, refreshToken } } }
    const payload = (data && data.data) || data;
    const tokens  = (payload && (payload.tokens || payload)) || {};
    const user    = (payload && payload.user) || null;
    const at      = tokens.accessToken;
    const rt      = tokens.refreshToken;

    if (!at) {
      console.error('[Login] No accessToken in response:', data);
      return err('Login succeeded but token missing — please retry.');
    }

    State.token = at;   // in-memory for WS/SSE ?token= param
    State.user  = user;

    console.log('[Login] Success →', user && user.email);
    await bootApp();
  } catch (e) {
    // ApiError has .code + .userMessage; fall back to generic
    const msg = (e && e.userMessage) || (e && e.message) || 'Sign-in failed. Please retry.';
    console.error('[Login] Failed:', e);
    err(msg);
  } finally {
    btn.disabled = false;
    btn.textContent = 'Sign In';
  }
}

async function bootApp() {
  // Hide login, show app
  document.getElementById('login-screen').style.display = 'none';
  document.getElementById('main-app').style.display = 'flex';

  // Update user info in sidebar
  if (State.user) {
    // /auth/me may return a user without firstName/lastName — fall back safely
    // so bootApp never throws (which would abort renderAllPages below).
    const initials = ((State.user?.firstName?.[0]) || (State.user?.lastName?.[0]) || (State.user?.email?.[0]) || 'U').toUpperCase();
    const fullName = [State.user.firstName, State.user.lastName].filter(Boolean).join(' ').trim() || State.user.email || 'User';
    const avEl   = document.getElementById('user-av');       if (avEl)   avEl.textContent   = initials;
    const nameEl = document.getElementById('user-name');     if (nameEl) nameEl.textContent = fullName;
    const roleEl = document.getElementById('user-email');    if (roleEl) roleEl.textContent = (State.user.role || '').replace('_', ' ');
    const metaEl = document.getElementById('nav-club-meta'); if (metaEl) metaEl.textContent = State.user.clubId ? 'Berlin · Manager' : '';
  }

  // Render all pages
  renderAllPages();

  // Phase A — hydrate tenant context (Club + Team) BEFORE list loads,
  // so SquadAPI can be scoped by the active team.
  try { await AppContext.load(); } catch (_) {}

  // Load data in parallel
  showToast('Loading your club data...', 'info');
  await loadAllData();

  // GPS simulator removed — startLiveGPS / startLiveInterval decommissioned.

  showToast(`Welcome back, ${State.user?.firstName}! ✅`, 'success');

  // Phase 12 — show Admin Center nav item only for CLUB_ADMIN / SUPER_ADMIN
  var role = State.user?.role;
  if (role === 'CLUB_ADMIN' || role === 'SUPER_ADMIN') {
    var navAdmin = document.getElementById('nav-admin');
    if (navAdmin) navAdmin.style.display = '';
  }
}

async function loadAllData() {
  try {
    const [analytics, players, matches, tourns, training] = await Promise.allSettled([
      api('/analytics/overview'),
      SquadAPI.list('limit=50' + (State.context && State.context.teamId ? '&teamId=' + encodeURIComponent(State.context.teamId) : '')),
      api('/matches?limit=20'),
      api('/training?limit=10'),
      api('/training/form'),
    ]);

    if (analytics.status === 'fulfilled' && analytics.value?.data) {
      State.analytics = analytics.value.data;
      renderDashboard();
    }

    if (players.status === 'fulfilled' && players.value?.data) {
      State.players = players.value.data;
      renderSquad();
      try { if (typeof renderAIScoutingCenter === 'function') renderAIScoutingCenter(); } catch (_) {}
      try { if (typeof renderAICoachCenter    === 'function') renderAICoachCenter();    } catch (_) {}
      try { if (typeof renderMedicalCenter    === 'function') renderMedicalCenter();    } catch (_) {}
      try { if (typeof renderPerformanceCenter === 'function') renderPerformanceCenter(); } catch (_) {}
      try { if (typeof renderScoutingCenter    === 'function') renderScoutingCenter();    } catch (_) {}
      try { if (typeof renderTransferCenter    === 'function') renderTransferCenter();    } catch (_) {}
      try { if (typeof renderFinanceCenter     === 'function') renderFinanceCenter();     } catch (_) {}
      try { if (typeof renderManagementCenter  === 'function') renderManagementCenter();  } catch (_) {}
      try { if (typeof renderAcademyCenter     === 'function') renderAcademyCenter();     } catch (_) {}
      try { if (typeof renderSportingDirectorCenter === 'function') renderSportingDirectorCenter(); } catch (_) {}
      try { if (typeof renderDirectorOfFootballCenter === 'function') renderDirectorOfFootballCenter(); } catch (_) {}
      try { if (typeof renderBoardOfDirectorsCenter   === 'function') renderBoardOfDirectorsCenter();   } catch (_) {}
      try { if (typeof renderOwnershipCenter          === 'function') renderOwnershipCenter();          } catch (_) {}
      try { if (typeof renderAIExecutiveCenter        === 'function') renderAIExecutiveCenter();        } catch (_) {}
      try { if (typeof renderAIPresidentCenter        === 'function') renderAIPresidentCenter();        } catch (_) {}
      try { if (typeof renderAIChairmanCenter         === 'function') renderAIChairmanCenter();         } catch (_) {}
      try { if (typeof renderAIWarRoom                === 'function') renderAIWarRoom();                } catch (_) {}
      try { if (typeof renderFOSCore                  === 'function') renderFOSCore();                  } catch (_) {}
      try { if (typeof renderFOSAIOrchestrator        === 'function') renderFOSAIOrchestrator();        } catch (_) {}
      try { if (typeof renderMultiClubNetwork         === 'function') renderMultiClubNetwork();         } catch (_) {}
      try { if (typeof renderFOSKnowledgeGraph        === 'function') renderFOSKnowledgeGraph();        } catch (_) {}
      try { if (typeof renderFOSNeuralIntelligence    === 'function') renderFOSNeuralIntelligence();    } catch (_) {}
      try { if (typeof renderFOSCommandCenter         === 'function') renderFOSCommandCenter();         } catch (_) {}
      try { if (typeof renderFOSAdminCenter           === 'function') renderFOSAdminCenter();           } catch (_) {}
      try { if (typeof renderFOSSecurityCenter        === 'function') renderFOSSecurityCenter();        } catch (_) {}
      try { if (typeof renderFOSDataCenter            === 'function') renderFOSDataCenter();            } catch (_) {}
      try { if (typeof renderFOSAutomationCenter      === 'function') renderFOSAutomationCenter();      } catch (_) {}
      try { if (typeof renderFOSIntelligencePipeline  === 'function') renderFOSIntelligencePipeline();  } catch (_) {}
      try { if (typeof renderFOSDecisionEngine        === 'function') renderFOSDecisionEngine();        } catch (_) {}
      try { if (typeof renderFOSEventBus              === 'function') renderFOSEventBus();              } catch (_) {}
      try { if (typeof renderFOSAuditGovernance       === 'function') renderFOSAuditGovernance();       } catch (_) {}
      try { if (typeof renderFOSRBAC                  === 'function') renderFOSRBAC();                  } catch (_) {}
      try { if (typeof renderFOSWorkflowExecution     === 'function') renderFOSWorkflowExecution();     } catch (_) {}
      try { if (typeof renderFOSDigitalTwin           === 'function') renderFOSDigitalTwin();           } catch (_) {}
      try { if (typeof renderFOSPredictiveIntelligence === 'function') renderFOSPredictiveIntelligence(); } catch (_) {}
      try { if (typeof renderFOSSimulationCenter      === 'function') renderFOSSimulationCenter();      } catch (_) {}
      try { if (typeof renderFOSExecutiveBridge       === 'function') renderFOSExecutiveBridge();       } catch (_) {}
      try { if (typeof renderFOSAIAgentFramework      === 'function') renderFOSAIAgentFramework();      } catch (_) {}
      try { if (typeof renderFOSObservability         === 'function') renderFOSObservability();         } catch (_) {}
      try { if (typeof renderGIS === 'function') { ['gis-data-lake','gis-analytics','gis-scouting','gis-medical','gis-financial','gis-performance'].forEach(function (k) { try { renderGIS(k); } catch (_) {} }); } } catch (_) {}
    }

    if (matches.status === 'fulfilled' && matches.value?.data) {
      State.matches = matches.value.data;
      renderMatches();
      try { if (typeof renderMatchCenter === 'function') renderMatchCenter(); } catch (_) {}
    }

    if (tourns.status === 'fulfilled' && tourns.value?.data) {
      State.training = tourns.value.data;
    }

    if (training.status === 'fulfilled' && training.value?.data) {
      State.trainingForm = training.value.data;
    }

    // Load analytics trend
    const trend = await api('/analytics/performance-trend?weeks=8');
    if (trend?.data) {
      State.performanceTrend = trend.data;
    }

  } catch (err) {
    console.error('Data load error:', err);
    showToast('Some data failed to load — showing cached data', 'error');
  }
}

function doLogout() {
  // POST to /auth/logout: server clears both HttpOnly cookies.
  api('/auth/logout', { method: 'POST' }).catch(() => {});
  // Close any open match WebSocket on logout.
  if (typeof _matchModalWS !== 'undefined' && _matchModalWS) {
    try { _matchModalWS.close(); } catch (_) {}
    _matchModalWS = null;
  }
  State.token = null;
  State.user  = null;

  document.getElementById('main-app').style.display = 'none';
  document.getElementById('login-screen').style.display = 'flex';
  showToast('Logged out successfully', 'info');
}

// ── COOKIE SESSION RESTORE ──
// The access_token HttpOnly cookie is sent automatically; the server validates
// it and returns the current user profile. No localStorage involved.
async function tryAutoLogin() {
  // One-time cleanup of orphaned tokens from the pre-cookie auth model.
  // Older builds stored JWTs in localStorage (fam_token / fam_refresh / fam_user).
  // This build authenticates via HttpOnly cookies + in-memory State.token and
  // never reads them, so any lingering values are stale/expired. Purge them so
  // they can never be mistaken for — or injected as — a live session.
  try {
    localStorage.removeItem('fam_token');
    localStorage.removeItem('fam_refresh');
    localStorage.removeItem('fam_user');
  } catch (_) {}
  try {
    const res = await fetch(API_BASE + '/auth/me', {
      credentials: 'include',
      headers: { 'Accept': 'application/json' },
    });
    if (res.ok) {
      const body = await res.json();
      const user = (body && (body.data || body)) || null;
      if (user && user.id) {
        State.user = user;
        // Populate the in-memory access token so the Authorization: Bearer
        // header is attached to subsequent cross-site API calls. The SPA
        // (familista-v5) and API (familista-backend) are different origins, so
        // the HttpOnly access_token cookie is a THIRD-PARTY cookie that the
        // browser may not send (third-party-cookie blocking / SameSite). Without
        // a Bearer fallback a restored session sends NO credentials and the API
        // replies "No token provided" (the Club page 401). /auth/refresh uses
        // the refresh_token cookie to mint a fresh access token we hold in memory.
        try {
          const rr = await fetch(API_BASE + '/auth/refresh', {
            method: 'POST',
            credentials: 'include',
            headers: { 'Accept': 'application/json' },
          });
          if (rr.ok) {
            const rd = await rr.json();
            const d  = (rd && (rd.data || rd)) || {};
            if (d.accessToken) State.token = d.accessToken;
          }
        } catch (_) { /* non-fatal: fall back to cookie auth */ }
        console.log('[AutoLogin] Session valid:', user.email, State.token ? '(bearer ready)' : '(cookie only)');
        bootApp();
        return;
      }
    }
    if (res.status === 401) {
      // Access token expired — try transparent cookie refresh
      const rr = await fetch(API_BASE + '/auth/refresh', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Accept': 'application/json' },
      });
      if (rr.ok) {
        const rd = await rr.json();
        const d  = (rd && (rd.data || rd)) || {};
        if (d.accessToken) State.token = d.accessToken;
        const mr = await fetch(API_BASE + '/auth/me', {
          credentials: 'include',
          headers: { 'Accept': 'application/json' },
        });
        if (mr.ok) {
          const mb = await mr.json();
          State.user = (mb && (mb.data || mb)) || null;
          if (State.user && State.user.id) { bootApp(); return; }
        }
      }
    }
    console.log('[AutoLogin] No valid session.');
  } catch (err) {
    console.warn('[AutoLogin] Network error.', err.message);
  }
}

// ── Form-safe render guards ──────────────────────────────────────────────────
// Prevents in-progress user input from being wiped by background re-renders.
//
// ARCHITECTURE: "is the user editing?" is tracked by an explicit body flag
// (`app-editing`) that a MutationObserver keeps in lock-step with the DOM.
// The observer watches every .modal-bg element for class changes, so EVERY
// open/close path — classList.add('open'), closeModal(), Escape, overlay click
// — flips the flag without us having to patch each call site. This is reliable
// even during focus transitions, where document.activeElement briefly parks on
// <body> and a naive .modal-bg.open / activeElement check would read false.

/**
 * ── THE single global guard ───────────────────────────────────────────────
 * isEditingUIActive() — true whenever any editing UI is open OR the user is
 * interacting with a form control. EVERY background render / navigation / poll
 * / WS / SSE entry point checks this before replacing innerHTML, so nothing the
 * user is looking at or typing into is ever torn down underneath them.
 *
 * Returns true when:
 *   • any .modal-bg.open exists (every modal / card detail / edit drawer)
 *   • body has the observer-maintained 'app-editing' flag
 *   • any open edit panel / drawer (defensive, non-.modal-bg variants)
 *   • activeElement is INPUT / TEXTAREA / SELECT / contenteditable
 *
 * NOTE: BUTTON is intentionally excluded from the focus check — filter pills,
 * tab buttons and nav buttons are themselves the legitimate triggers of a
 * re-render, so treating a focused button as "editing" would break them.
 */
function isEditingUIActive() {
  // 1. Observer-maintained flag (primary truth, survives focus transitions)
  if (document.body.classList.contains('app-editing')) return true;
  // 2. Any modal / card detail / edit drawer overlay
  if (document.querySelector('.modal-bg.open')) return true;
  // 3. Defensive: any open edit panel / drawer that isn't a .modal-bg
  if (document.querySelector('.drawer.open, .edit-panel.open, [id*="edit"][class*="open"], [id*="drawer"][class*="open"]')) return true;
  // 4. Any focused text/select control (inline filters, search, AI chat, forms)
  var ae = document.activeElement;
  if (ae && ae !== document.body) {
    var tag = ae.tagName;
    if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
    if (ae.isContentEditable) return true;
  }
  return false;
}

// Aliases — all existing call sites delegate to the one central guard.
function _isModalOpen()      { return isEditingUIActive(); }
function isFormEditing()     { return isEditingUIActive(); }
function _isAnyFormEditing() { return isEditingUIActive(); }

/**
 * Keep document.body.classList('app-editing') synchronised with the real DOM.
 * One MutationObserver on every .modal-bg element fires on each class change,
 * so the flag is always correct regardless of how the modal was opened/closed.
 * When editing ends, flush any render that was deferred while it was active.
 */
(function _wireModalState() {
  function sync() {
    var open = !!document.querySelector('.modal-bg.open');
    var was  = document.body.classList.contains('app-editing');
    document.body.classList.toggle('app-editing', open);
    if (was && !open) _flushPendingRender();   // editing just ended → catch up
  }
  function attach() {
    var obs = new MutationObserver(sync);
    document.querySelectorAll('.modal-bg').forEach(function (m) {
      obs.observe(m, { attributes: true, attributeFilter: ['class'] });
    });
    sync();
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', attach);
  } else {
    attach();
  }
})();

// ─── Deep Space Neural Network theme activation ────────────────────────
// Activates the FOS visual theme on <body> AND (Phase B.1) the new
// Premium Club Theme. Both classes coexist; club-theme rules ship at the
// end of app.css and win via cascade source order. The Deep Space Neural
// look stays available for any future opt-out — flip `body.fos-neural-theme`
// off if you ever want the bare theme.
(function () {
  function applyTheme() {
    try {
      if (!document.body) return;
      if (!document.body.classList.contains('fos-neural-theme')) {
        document.body.classList.add('fos-neural-theme');
      }
      // Phase B.1 — premium club theme (default on)
      if (!document.body.classList.contains('club-theme')) {
        document.body.classList.add('club-theme');
      }
    } catch (_) {}
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', applyTheme);
  } else {
    applyTheme();
  }
})();

// ── Club Workspace nav config ─────────────────────────────────────────────────
// Each entry defines one sidebar item in the CLUB WORKSPACE section.
//
// Fields:
//   slug    — page slug; MUST also appear in _ALLOWED_PAGES and _buildPageTemplateMap
//   label   — text shown in the sidebar
//   svgPath — a single heroicons-style <path d="…"> for a 20×20 icon
//   color   — CSS color/variable for the icon tint (leave '' for theme default)
//   enabled — set false to hide without deleting (default true)
//   order   — ascending sort order
//
// ▶ TO ADD A NEW TAB:
//   1. Push a new object to CLUB_NAV_ITEMS with a unique slug.
//   2. Add the slug to _ALLOWED_PAGES (search "_ALLOWED_PAGES" below).
//   3. Add a renderXxxHTML function and register it in _buildPageTemplateMap.
//   4. If the page needs data, add a loadXxxData() call in the navTo lazy-load block.
//
var CLUB_NAV_ITEMS = [
  {
    slug:    'club-home',
    label:   'Home',
    svgPath: 'M10 1.944A11.954 11.954 0 012.166 5C2.056 5.649 2 6.319 2 7c0 5.225 3.34 9.67 8 11.317C14.66 16.67 18 12.225 18 7c0-.682-.057-1.35-.166-2.001A11.954 11.954 0 0110 1.944z',
    color:   'var(--pitch-400,#4ade80)',
    enabled: true,
    order:   1,
  },
  {
    slug:    'squad',
    label:   'Squad',
    svgPath: 'M13 6a3 3 0 11-6 0 3 3 0 016 0zM18 8a2 2 0 11-4 0 2 2 0 014 0zM14 15a4 4 0 00-8 0v3h8v-3zM6 8a2 2 0 11-4 0 2 2 0 014 0zM16 18v-3a5.972 5.972 0 00-.75-2.906A3.005 3.005 0 0119 15v3h-3zM4.75 12.094A5.973 5.973 0 004 15v3H1v-3a3 3 0 013.75-2.906z',
    color:   '#38bdf8',
    enabled: true,
    order:   2,
  },
];

// Render CLUB_NAV_ITEMS into #workspace-nav-items in the sidebar.
// Called once at boot; call again after mutating CLUB_NAV_ITEMS at runtime.
function buildWorkspaceSidebar() {
  var slot = document.getElementById('workspace-nav-items');
  if (!slot) return;
  var items = CLUB_NAV_ITEMS
    .filter(function (n) { return n.enabled !== false; })
    .sort(function (a, b) { return (a.order || 0) - (b.order || 0); });
  slot.innerHTML = items.map(function (n) {
    var iconStyle = n.color ? ' style="color:' + n.color + '"' : '';
    return '<div class="nav-item nav-item--workspace" data-nav="' + n.slug
      + '" data-page="' + n.slug + '">'
      + '<svg class="nav-icon" fill="currentColor" viewBox="0 0 20 20"' + iconStyle + '>'
      + '<path d="' + n.svgPath + '"/></svg>'
      + '<span class="nav-label">' + n.label + '</span>'
      + '</div>';
  }).join('');
}
(function () {
  function _boot() { try { buildWorkspaceSidebar(); } catch (_) {} }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', _boot);
  } else { _boot(); }
})();

// ── Home Dashboard widget config ─────────────────────────────────────────────
// Drives the Club Home dashboard grid. Each entry = one card on the page.
//
// Fields:
//   id         — unique key; must match a key in HOME_WIDGET_RENDERERS
//   title      — header label (hidden when hideHeader: true)
//   svgPath    — heroicons 20×20 <path d="…"> for the widget icon
//   color      — CSS color / var() applied as icon tint and accent
//   enabled    — false hides without deleting
//   order      — ascending render order
//   cols       — grid-column span out of 12  (1–12, default 6)
//   hideHeader — omit the title bar (widget IS the visual header)
//
// ▶ TO ADD A WIDGET:
//   1. Push an entry here with a unique id.
//   2. Add a matching key → function in HOME_WIDGET_RENDERERS below.
//   3. Implement renderWidget_<camelId>(ctx) → HTML string.
//
var HOME_WIDGETS = [
  { id:'club-header',       title:'Club Header',        svgPath:'M10 1.944A11.954 11.954 0 012.166 5C2.056 5.649 2 6.319 2 7c0 5.225 3.34 9.67 8 11.317C14.66 16.67 18 12.225 18 7c0-.682-.057-1.35-.166-2.001A11.954 11.954 0 0110 1.944z',                                                                                                                                                                                                                                                                                                                color:'var(--pitch-400,#4ade80)',  enabled:true, order:1, cols:12, hideHeader:true },
];


// ── Widget render functions ───────────────────────────────────────────────────
// Each: renderWidget_<id>(ctx) → HTML string
// ctx  = live app state: { club:{id,name,emblem,shortName}, user:{...} }
// Data = CLUB_HOME_DATA sections — replace each section with an API fetch when ready.
//
// ▶ Add new renderer functions here, then register in HOME_WIDGET_RENDERERS below.

function renderWidget_clubHeader(ctx) {
  var club   = ctx.club || {};
  var user   = ctx.user || {};
  var d      = ctx.data && ctx.data.header;
  var info   = ctx.data && ctx.data.info;
  var name   = (d && d.clubName)  || club.name      || 'Club';
  var short  = (d && d.shortName) || club.shortName  || '';
  var owner  = (d && d.ownerName) || [user.firstName, user.lastName].filter(Boolean).join(' ') || user.email || 'Owner';
  var season = (info && info.season) || '';
  var emb    = (d && d.emblem)    || club.emblem || '';
  var crest  = emb
    ? '<img src="' + _esc(emb) + '" class="chd-hero-crest" onerror="this.style.display=\'none\'">'
    : '<div class="chd-hero-crest chd-hero-crest--text">⚽</div>';
  return '<div class="chd-hero-inner">'
    + crest
    + '<div class="chd-hero-text">'
    +   '<h1 class="chd-hero-name">' + _esc(name) + '</h1>'
    +   (short ? '<span class="chd-hero-short">' + _esc(short) + '</span>' : '')
    +   '<div class="chd-hero-meta">'
    +     '<span class="chd-hero-meta-item">👤 ' + _esc(owner) + '</span>'
    +     (season ? '<span class="chd-hero-meta-sep">·</span><span class="chd-hero-meta-item">📅 ' + _esc(season) + '</span>' : '')
    +   '</div>'
    + '</div>'
    + '</div>';
}

// Registry: widget id → render function
// ▶ Register new renderers here after adding to HOME_WIDGETS above.
var HOME_WIDGET_RENDERERS = {
  'club-header': renderWidget_clubHeader,
};

// ── Phase B · Area separation (Owner / System / Club) ────────────
// `home`   = Owner Home or Clubs picker — sidebar hidden
// `system` = System area — only platform/system nav items visible
// `club`   = Club workspace — only club nav items visible
function _areaForPage(page) {
  var p = String(page || '').toLowerCase();
  if (p === 'owner-home' || p === 'clubs') return 'home';
  if (p.indexOf('fos-') === 0) return 'system';
  if (p === 'multi-club-network') return 'system';
  if (p.indexOf('gis-') === 0) return 'system';
  return 'club';
}
function _setArea(area) {
  if (!document.body) return;
  var classes = document.body.classList;
  classes.remove('area-home', 'area-system', 'area-club');
  classes.add('area-' + (area || 'home'));
}
// Initial area on boot — Owner Home is the landing surface.
(function () {
  function init() { try { _setArea('home'); } catch (_) {} }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else { init(); }
})();

// ── Topbar context Back button ─────────────────────────────────
// Shows nothing on Owner Home; "Owner Home" on System pages; "Clubs"
// on Club Workspace pages. The handler in the click dispatcher
// (case 'topbarBack') reads the current area and routes back.
function _updateTopbarBack(page) {
  var btn = document.getElementById('topbar-back');
  var lbl = document.getElementById('topbar-back-label');
  if (!btn) return;
  var area = _areaForPage(page);
  if (area === 'home') {
    btn.style.display = 'none';
    return;
  }
  btn.style.display = '';
  if (lbl) lbl.textContent = (area === 'system') ? 'Owner Home' : 'Clubs';
}

// ── Browser back/forward — popstate replays navigation ─────────
(function () {
  function onPopState(e) {
    var page = (e && e.state && e.state.page) ||
               (location.hash || '').replace(/^#/, '') ||
               'owner-home';
    try { navTo(page, null, { fromPopState: true }); } catch (_) {}
  }
  function initHash() {
    try {
      var hashPage = (location.hash || '').replace(/^#/, '');
      if (hashPage) {
        // Deep-link arrived; route to it (also runs through the
        // allow-list guard inside navTo).
        navTo(hashPage, null, { fromPopState: false });
      } else if (window.history && !window.history.state) {
        // Seed history so the very first Back press has somewhere
        // to land instead of leaving the app.
        window.history.replaceState({ page: 'owner-home' }, '', '#owner-home');
      }
    } catch (_) {}
  }
  if (typeof window !== 'undefined') {
    window.addEventListener('popstate', onPopState);
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initHash);
  } else { initHash(); }
})();

// ── Onboard New Club modal ─────────────────────────────────────
// Replaces the previous behaviour of routing the Clubs picker's
// "+ Onboard a new club" tile straight to the Multi-Club Management
// platform page. Opens a clear modal with Cancel + Submit. Submit
// shows a toast explaining backend admin must complete provisioning;
// no backend / API / DB write is performed here.
function openOnboardClubModal() {
  var el = document.getElementById('onboard-club-modal');
  if (!el) return;
  el.classList.add('open');
  // Reset inputs (idempotent in case the modal is re-opened)
  ['onboard-name','onboard-shortname','onboard-city','onboard-country','onboard-emblem']
    .forEach(function (id) { var f = document.getElementById(id); if (f) f.value = ''; });
  setTimeout(function () { var n = document.getElementById('onboard-name'); if (n) n.focus(); }, 50);
}
function closeOnboardClubModal() {
  var el = document.getElementById('onboard-club-modal');
  if (el) el.classList.remove('open');
}
// Submit the Onboard New Club form.
// Calls POST /clubs which (a) creates the Club row and (b) grants the caller
// a CLUB_OWNER Membership in that club. On success, reloads /me/context so
// State.context.availableClubs picks up the new club, then re-renders the
// Clubs picker — the new card appears next to FC Familista.
function submitOnboardClub() {
  var nameEl  = document.getElementById('onboard-name');
  var cityEl  = document.getElementById('onboard-city');
  var shortEl = document.getElementById('onboard-shortname');
  var ctryEl  = document.getElementById('onboard-country');
  var embEl   = document.getElementById('onboard-emblem');
  var submitBtn = document.querySelector('#onboard-club-modal [data-action="submitOnboardClub"]');

  var name  = (nameEl  && nameEl.value  || '').trim();
  var city  = (cityEl  && cityEl.value  || '').trim();
  var shortName = (shortEl && shortEl.value || '').trim();
  var country   = (ctryEl  && ctryEl.value  || '').trim();
  var emblem    = (embEl   && embEl.value   || '').trim();

  if (!name) { try { showToast('Club name is required.', 'warn', 3000); } catch (_) {} if (nameEl) nameEl.focus(); return; }
  if (!city) { try { showToast('City is required.', 'warn', 3000); } catch (_) {} if (cityEl) cityEl.focus(); return; }
  if (emblem && !/^https:\/\//i.test(emblem)) {
    try { showToast('Emblem URL must start with https://', 'warn', 3500); } catch (_) {}
    if (embEl) embEl.focus();
    return;
  }

  var payload = { name: name, city: city };
  if (shortName) payload.shortName = shortName;
  if (country)   payload.country   = country;
  if (emblem)    payload.emblem    = emblem;

  // Disable submit during the round-trip so a double-click can't create two clubs.
  if (submitBtn) { submitBtn.disabled = true; submitBtn.textContent = 'Creating…'; }

  FamilistaAPI.post('/clubs', payload).then(function (res) {
    // sendSuccess wraps as { success, data, message } — FamilistaAPI normalises.
    var data = (res && res.data) || res || {};
    var profile = data.profile || {};
    var newClubId = data.clubId || profile.id || null;

    // ── Defence in depth ─────────────────────────────────────────────
    // Splice the new club directly from the POST response into
    // State.context.availableClubs, so the picker repaints with both
    // cards even if the /me/context refresh below fails (cold start,
    // token expiry, edge cache, etc.).
    try {
      State.context = State.context || { clubId: null, teamId: null, availableClubs: [] };
      if (!Array.isArray(State.context.availableClubs)) State.context.availableClubs = [];
      if (newClubId && !State.context.availableClubs.find(function (c) { return c && c.id === newClubId; })) {
        State.context.availableClubs.push({
          id:        newClubId,
          name:      profile.name      || name,
          shortName: profile.shortName || shortName || null,
          emblem:    profile.emblem    || emblem    || null,
          city:      profile.city      || city      || null,
          country:   profile.country   || country   || null,
          plan:      profile.plan      || 'BASIC',
          teams:     [],
          isActive:  true,
        });
      }
    } catch (e) { try { console.warn('[onboard-club] splice failed:', e); } catch (_) {} }

    // Refresh /me/context so availableClubs is the authoritative server view
    // (replaces our optimistic splice with the canonical shape).
    return (typeof AppContext !== 'undefined' && AppContext.load ? AppContext.load() : Promise.resolve()).then(function () {
      // Re-render the picker if it's currently mounted.
      try { if (typeof renderClubs === 'function') renderClubs(); } catch (_) {}
      try { showToast('Club "' + name + '" created.', 'success', 3500); } catch (_) {}
      closeOnboardClubModal();
      return newClubId;
    });
  }).catch(function (err) {
    var msg = (err && (err.userMessage || err.message)) || 'Failed to create club';
    try { showToast(msg, 'error', 4500); } catch (_) {}
    console.warn('[onboard-club] failed:', err);
  }).then(function () {
    if (submitBtn) { submitBtn.disabled = false; submitBtn.textContent = 'Submit request'; }
  });
}

// Open a Club workspace from the Clubs picker.
// 1. Calls POST /me/context with the picked clubId so server-side context
//    matches what the user sees.
// 2. Mirrors the change into the local State so renderers pick it up.
// 3. Navigates to the Dashboard.
function openClub(clubId) {
  if (!clubId) {
    try { showToast('Missing club id', 'error'); } catch (_) {}
    return;
  }
  var goToDashboard = function () {
    try { window.State = window.State || {}; window.State.context = window.State.context || {}; window.State.context.clubId = clubId; window.State.context.teamId = null; } catch (_) {}
    try { navTo('club-home', null); } catch (_) {}
  };
  // If AppContext is available, route through it so /me/context is updated
  // server-side and AppContext._ctx stays consistent with the picker choice.
  if (typeof AppContext !== 'undefined' && AppContext.switchClub) {
    try {
      var p = AppContext.switchClub(clubId);
      if (p && typeof p.then === 'function') { p.then(goToDashboard).catch(goToDashboard); }
      else { goToDashboard(); }
    } catch (_) { goToDashboard(); }
  } else {
    goToDashboard();
  }
}

// ── Phase B.1 · Topbar brand hydration ────────────────────────────
// Keeps the topbar's emblem + subtitle in sync with the loaded tenant
// (State.club) and the current page (platform vs club workspace). No
// new endpoints — reads the same State the rest of the app uses.
function _b1IsPlatformPage(page) {
  var p = String(page || '').toLowerCase();
  return p.indexOf('fos-') === 0 || p === 'multi-club-network';
}
function hydrateTopbarBrand(page) {
  try {
    var emblemEl   = document.getElementById('topbar-club-emblem');
    var subtitleEl = document.getElementById('page-subtitle');
    var clubName = (window.State && State.club && State.club.name) || 'FC Familista';
    var emblemUrl = (window.State && State.club && State.club.emblem) || '';
    if (subtitleEl) {
      subtitleEl.textContent = _b1IsPlatformPage(page) ? 'PLATFORM' : clubName;
    }
    if (emblemEl) {
      // If a real emblem URL is loaded, render the image. Otherwise leave
      // the fallback glyph in place — no fabricated club identity.
      if (emblemUrl) {
        if (emblemEl.tagName !== 'IMG') {
          var img = document.createElement('img');
          img.id = 'topbar-club-emblem';
          img.className = 'topbar-emblem';
          img.alt = clubName;
          img.src = emblemUrl;
          img.onerror = function () {
            // Restore glyph fallback on broken image
            var span = document.createElement('span');
            span.id = 'topbar-club-emblem';
            span.className = 'topbar-emblem';
            span.setAttribute('aria-hidden', 'true');
            span.textContent = '⚽';
            img.replaceWith(span);
          };
          emblemEl.replaceWith(img);
        } else if (emblemEl.getAttribute('src') !== emblemUrl) {
          emblemEl.setAttribute('src', emblemUrl);
          emblemEl.setAttribute('alt', clubName);
        }
      }
    }
    // Document title — reflects active page + tenant.
    try {
      var titleEl = document.getElementById('page-title');
      var pageLabel = (titleEl && titleEl.textContent) || 'Familista';
      document.title = pageLabel + ' — ' + clubName;
    } catch (_) {}
  } catch (_) {}
}

