    + '<div class="sqment-sw-col sqment-sw-col--w"><h5>Weaknesses</h5>' + sw.weaknesses.map(function (x) { return '<div class="sqment-sw-li"><span>' + x[0] + '</span><b>' + x[1] + '%</b></div>'; }).join('') + '</div></div>';
